mapper.select:
SELECT  tt.team_id,  tt.team_name, tt.leader_name, tt.team_person, tt.begin_date,  tt.end_date, tt.apply_time, tt.team_status,tt.ref_mch
FROM    travel_team tt WHERE 1=1 AND tt.user_id = #{userId}

    AND tt.team_id = #{teamId}


    AND tt.team_status = #{teamStatus}


    AND tt.leader_name LIKE  concat(concat('%',#{leadName),'%')


    AND tt.ref_mch LIKE  concat(concat('%',#{refMch}),'%')


     AND mtpr.submit_time >= DATE_FORMAT(#{beginDate},'%Y-%m-%d %H:%i:%S')


     AND mtpr.submit_time <= DATE_FORMAT(#{endDate},'%Y-%m-%d %H:%i:%S')

ORDER BY tt.apply_time DESC
